// Recebe item unico do WF3 caller com atestados_para_upload[] + binaries.
// Emite N items, 1 por atestado, com binary normalizado em key '0'.
// Se algum binary nao chegar, retorna erro bloqueante estruturado.
const input = $input.first();
const hist = input.json || {};
const binary = input.binary || {};
const atestados = Array.isArray(hist.atestados_para_upload) ? hist.atestados_para_upload : [];
const out = [];
for (const a of atestados) {
  const binaryName = a.binary_name || ('atestado_' + a.id);
  const bin = binary[binaryName];
  const base = { atestado_id: a.id, data_inicio: a.data_inicio, data_fim: a.data_fim, tipo_documento: a.tipo_documento || a.tipoDocumento || 'atestado', periodos: Array.isArray(a.periodos) ? a.periodos : [], primeiro_dia_foi_trabalhar: a.primeiro_dia_foi_trabalhar, primeiro_dia_trabalhou_seis_horas: a.primeiro_dia_trabalhou_seis_horas, nome_arquivo: a.nome_arquivo, tamanho_arquivo: a.tamanho_arquivo, hist_uuid: hist.uuid, hist_item_id: hist.item_id, hist_nome: hist.nome, hist_contrato: hist.contrato, historico_file_column: a.historico_file_column || 'file_mm3cvt54', binary_name: binaryName };
  if (!bin) { out.push({ json: { ...base, _erro: true, _erro_code: 'arquivo_ausente', _erro_etapa: 'receber_arquivo_atestado', _erro_msg: 'Binary ausente no subworkflow: ' + binaryName } }); continue; }
  out.push({ json: base, binary: { '0': bin } });
}
if (atestados.length > 0 && out.length === 0) return [{ json: { _erro: true, _erro_code: 'arquivo_ausente', _erro_etapa: 'expandir_atestados', _erro_msg: 'Nenhum arquivo de atestado chegou ao subworkflow.' } }];
return out;

// Monta GraphQL create_item no board Controle de Atestados.
const BOARD_CONTROLE = 18298015951;
const GROUP_CONTROLE = 'topics';
const a = $json;
if (a._erro) return [{ json: { ...a, queryControle: 'query { me { id } }', skip_http: true }, binary: $binary }];
const meses = ['JANEIRO','FEVEREIRO','MAR\u00c7O','ABRIL','MAIO','JUNHO','JULHO','AGOSTO','SETEMBRO','OUTUBRO','NOVEMBRO','DEZEMBRO'];
function br(iso) { if (!iso) return ''; const parts = iso.split('-'); return parts[2] + '/' + parts[1] + '/' + parts[0]; }
function dias(inicio, fim) { const out = []; const cur = new Date(inicio + 'T00:00:00Z'); const end = new Date(fim + 'T00:00:00Z'); while (cur <= end) { out.push(cur.toISOString().slice(0,10)); cur.setUTCDate(cur.getUTCDate()+1); } return out; }
function contratoLabel(v) { const s = String(v || '').toUpperCase().trim(); if (s.includes('DETRAN')) return 'DETRAN'; if (s.includes('TRE')) return 'TRE PB'; if (s.includes('SEMSA')) return 'SEMSA'; if (s.includes('CETAM')) return 'CETAM'; if (s.includes('INTERIOR')) return 'SEDUC INTERIOR'; if (s.includes('COORDENADORIA')) return 'SEDUC COORDENADORIAS'; if (s.includes('ESCOLA')) return 'SEDUC ESCOLA'; return s || 'SEDUC SEDE'; }
function labelHoras(a) { if (!a.primeiro_dia_foi_trabalhar) return 'N\u00e3o se aplica'; if (a.primeiro_dia_trabalhou_seis_horas === true) return 'Trabalhou +6h'; if (a.primeiro_dia_trabalhou_seis_horas === false) return 'Trabalhou -6h'; return 'N\u00e3o se aplica'; }
const datas = dias(a.data_inicio, a.data_fim);
const mesIndex = Number(String(a.data_inicio).slice(5,7)) - 1;
const competencia = meses[mesIndex] || '';
const columnValues = { single_select5yq25pm: { label: 'INTERMITENTE' }, sele__o_individual__1: { label: a.tipo_documento === 'declaracao' ? 'Declaracao de Comparecimento' : 'Atestado M\u00e9dico' }, numberjox5johv: String(datas.length), short_textcpcyzaec: br(a.data_inicio) + ' a ' + br(a.data_fim), date: { date: a.data_inicio }, single_selectkiwkh2d: { label: 'NDA' }, single_selectcovdz0i: { label: labelHoras(a) }, sele__o_individual8__1: { label: 'Sem acompanhamento' }, department: { label: contratoLabel(a.hist_contrato) }, short_textl33u569o: 'Convocacao ' + a.hist_uuid + ' | Historico ' + a.hist_item_id + ' | ' + a.data_inicio + ' a ' + a.data_fim + (a.tipo_documento === 'declaracao' ? ' | Declaracao: ' + (a.periodos || []).join('+') : ''), color_mky1mjh7: { label: 'VALIDADO' }, status: { label: 'VERIFICAR' }, color_mkzbgzc6: { label: 'AGUARDANDO RETORNO' } };
if (competencia) columnValues.dropdown_mkzsebbf = { labels: [competencia] };
const escaped = JSON.stringify(JSON.stringify(columnValues));
const query = 'mutation { create_item(board_id: ' + BOARD_CONTROLE + ', group_id: ' + JSON.stringify(GROUP_CONTROLE) + ', item_name: ' + JSON.stringify(a.hist_nome) + ', column_values: ' + escaped + ', create_labels_if_missing: true) { id } }';
return [{ json: { ...$json, queryControle: query }, binary: $binary }];

const BOARD_CONTROLE = 18298015951;
const r = $json;
const all = $('Preparar Create Item Controle').all();
const idx = $itemIndex;
const prep = all[idx]?.json || {};
const bin = all[idx]?.binary || {};
if (prep._erro) return [{ json: { ...prep, monday_item_id: null, monday_item_url: null }, binary: bin }];
const itemId = r?.data?.create_item?.id || r?.body?.data?.create_item?.id || null;
const errors = r?.errors || r?.body?.errors || r?.error || null;
function detalhe(v) { try { return typeof v === 'string' ? v : JSON.stringify(v); } catch { return String(v); } }
function mondayCode(msg) { const s = String(msg || '').toLowerCase(); if (s.includes('permission') || s.includes('permiss') || s.includes('credential') || s.includes('unauthorized') || s.includes('forbidden')) return 'erro_monday_permissao'; if (s.includes('rate') || s.includes('limit') || s.includes('complexity') || s.includes('too many')) return 'erro_monday_limite'; return 'erro_criar_atestado_monday'; }
if (!itemId) { const msg = detalhe(errors || 'Sem id retornado ao criar item no Controle de Atestados'); return [{ json: { ...prep, _erro: true, _erro_code: mondayCode(msg), _erro_etapa: 'criar_atestado_controle', _erro_msg: msg, monday_item_id: null, monday_item_url: null }, binary: bin }]; }
return [{ json: { ...prep, monday_item_id: String(itemId), monday_item_url: 'https://contato-serv.monday.com/boards/' + BOARD_CONTROLE + '/pulses/' + itemId }, binary: bin }];

const fileMutation = 'mutation ($file: File!, $item_id: ID!, $column_id: String!) { add_file_to_column(item_id: $item_id, column_id: $column_id, file: $file) { id } }';
const a = $json;
if (a._erro) return [{ json: { ...a, upload_controle_query: 'query { me { id } }', upload_controle_variables: '{}', upload_controle_map: '{}', skip_http: true }, binary: $binary }];
return [{ json: { ...a, upload_controle_query: fileMutation, upload_controle_variables: JSON.stringify({ file: null, item_id: a.monday_item_id, column_id: 'files' }), upload_controle_map: JSON.stringify({ '0': ['variables.file'] }) }, binary: $binary }];

const all = $('Preparar Upload Controle').all();
const idx = $itemIndex;
const prep = all[idx]?.json || {};
const bin = all[idx]?.binary || {};
if (prep._erro) return [{ json: { ...prep, upload_controle_ok: false }, binary: bin }];
const respUpload = $json;
const uploadOK = !!(respUpload?.data?.add_file_to_column?.id || respUpload?.body?.data?.add_file_to_column?.id);
const uploadErrors = respUpload?.errors || respUpload?.body?.errors || respUpload?.error || null;
const fileMutation = 'mutation ($file: File!, $item_id: ID!, $column_id: String!) { add_file_to_column(item_id: $item_id, column_id: $column_id, file: $file) { id } }';
return [{ json: { ...prep, upload_controle_ok: uploadOK, upload_controle_error: uploadOK ? null : uploadErrors, upload_historico_query: fileMutation, upload_historico_variables: JSON.stringify({ file: null, item_id: prep.hist_item_id, column_id: prep.historico_file_column }), upload_historico_map: JSON.stringify({ '0': ['variables.file'] }) }, binary: bin }];

const prepNodeName = 'Preparar Upload Histórico';
const all = $(prepNodeName).all();
const respostas = $input.all();
function detalhe(v) { if (!v) return null; try { return typeof v === 'string' ? v : JSON.stringify(v); } catch { return String(v); } }
function mondayCode(msg, fallback) { const s = String(msg || '').toLowerCase(); if (s.includes('permission') || s.includes('permiss') || s.includes('credential') || s.includes('unauthorized') || s.includes('forbidden')) return 'erro_monday_permissao'; if (s.includes('rate') || s.includes('limit') || s.includes('complexity') || s.includes('too many')) return 'erro_monday_limite'; return fallback; }
const atestados_enriquecidos = [];
const errors = [];
for (let i = 0; i < all.length; i++) {
  const prep = all[i].json;
  const resp = respostas[i]?.json || {};
  const uploadHistOK = !!(resp?.data?.add_file_to_column?.id || resp?.body?.data?.add_file_to_column?.id);
  const uploadHistError = resp?.errors || resp?.body?.errors || resp?.error || null;
  atestados_enriquecidos.push({ id: prep.atestado_id, data_inicio: prep.data_inicio, data_fim: prep.data_fim, tipo_documento: prep.tipo_documento || 'atestado', periodos: Array.isArray(prep.periodos) ? prep.periodos : [], primeiro_dia_foi_trabalhar: prep.primeiro_dia_foi_trabalhar, primeiro_dia_trabalhou_seis_horas: prep.primeiro_dia_trabalhou_seis_horas, nome_arquivo: prep.nome_arquivo, tamanho_arquivo: prep.tamanho_arquivo, monday_item_id: prep.monday_item_id || null, monday_item_url: prep.monday_item_url || null, upload_controle_ok: prep.upload_controle_ok ?? false, upload_historico_ok: uploadHistOK });
  if (prep._erro) errors.push({ erro: prep._erro_code || 'erro_criar_atestado_monday', atestado_id: prep.atestado_id, etapa: prep._erro_etapa || 'criar_atestado_controle', detalhe_tecnico: prep._erro_msg });
  if (prep.monday_item_id && !prep.upload_controle_ok) errors.push({ erro: mondayCode(detalhe(prep.upload_controle_error), 'erro_anexar_controle'), atestado_id: prep.atestado_id, etapa: 'anexar_controle', detalhe_tecnico: detalhe(prep.upload_controle_error) || 'Upload no Controle de Atestados falhou' });
  if (prep.monday_item_id && !uploadHistOK) errors.push({ erro: mondayCode(detalhe(uploadHistError), 'erro_anexar_historico'), atestado_id: prep.atestado_id, etapa: 'anexar_historico', detalhe_tecnico: detalhe(uploadHistError) || 'Upload no Histórico falhou' });
}
return [{ json: { ok: errors.length === 0, atestados_processados: atestados_enriquecidos.length, atestados_enriquecidos, errors } }];

const agg = $('Aggregar Resultados').first().json;
function msg(code) {
  const map = {
    erro_criar_atestado_monday: 'Nao foi possivel criar o registro do atestado no Monday.',
    erro_anexar_controle: 'Nao foi possivel anexar o arquivo no Controle de Atestados.',
    erro_anexar_historico: 'Nao foi possivel anexar o arquivo no Historico.',
    erro_atualizar_historico: 'O atestado foi processado, mas nao foi possivel atualizar o Historico.',
    erro_monday_permissao: 'O Monday recusou a operacao por permissao ou credencial.',
    erro_monday_limite: 'O Monday limitou a requisicao. Tente novamente em alguns minutos.',
    erro_interno_atestado: 'Erro interno ao processar o atestado.'
  };
  return map[code] || map.erro_interno_atestado;
}
if (!agg.ok) {
  const first = agg.errors?.[0] || {};
  const code = first.erro || 'erro_interno_atestado';
  return [{ json: {
    ok: false,
    _statusCode: code === 'erro_monday_limite' ? 429 : 500,
    erro: code,
    mensagem: msg(code),
    atestado_id: first.atestado_id || null,
    etapa: first.etapa || 'processar_atestado',
    detalhe_tecnico: first.detalhe_tecnico || JSON.stringify(agg.errors || []),
    notificar_whatsapp: true
  } }];
}
return [{ json: {
  ok: true,
  atestados_processados: agg.atestados_processados,
  atestados_enriquecidos: agg.atestados_enriquecidos
} }];
